class Solution {
    public int calculate(String s) {
        int num = 0, sum = 0, sign = 1, mul = 1;
        for (char c : s.toCharArray()) {
            if (Character.isDigit(c)) {
                num = num * 10 + c - '0';
            } else if (c == ' ') {
                continue;
            } else {
                sum += sign * num;
                num = 0;
                if (c == '+') {
                    sign = 1;
                } else if (c == '-') {
                    sign = -1;
                } else if (c == '*') {
                    mul = 1;
                } else {
                    sum += sign * (mul * num);
                    num = 0;
                    sign = 1;
                    mul = 1;
                }
            }
        }
        sum += sign * num;
        return sum;
    }
}
